css:
body {
    margin: 0;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
    background-color: #fffbeb;
    color: #451a03;
}

.header {
    background-color: #ffffff;
    border-bottom: 2px solid #fcd34d;
    padding: 16px 24px;
}

.header-container {
    max-width: 1200px;
    margin: 0 auto;
    display: flex;
    align-items: center;
    gap: 16px;
}

.logo {
    width: 60px;
    height: 60px;
    border-radius: 12px;
    object-fit: cover;
    border: 2px solid #d97706;
}

.brand h1 {
    font-size: 22px;
    margin: 0 0 2px 0;
    font-weight: 900;
}

.brand p {
    margin: 0;
    font-size: 13px;
    color: #b45309;
}

.hero {
    background: linear-gradient(135deg, #d97706 0%, #b45309 100%);
    color: white;
    text-align: center;
    padding: 60px 20px;
}

.hero h2 {
    font-size: 32px;
    margin: 0 0 8px 0;
    font-weight: 800;
}

.hero p {
    margin: 0;
    font-size: 16px;
    opacity: 0.95;
}

.container {
    max-width: 1200px;
    margin: 40px auto;
    padding: 0 24px;
}

.filters {
    display: flex;
    justify-content: center;
    gap: 10px;
    margin-bottom: 35px;
    flex-wrap: wrap;
}

.filter-btn {
    background: #ffffff;
    border: 1px solid #fcd34d;
    color: #78350f;
    padding: 10px 20px;
    border-radius: 30px;
    font-weight: 700;
    font-size: 14px;
    cursor: pointer;
    transition: all 0.2s;
}

.filter-btn:hover, .filter-btn.active {
    background: #d97706;
    color: white;
    border-color: #d97706;
}

.menu-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(280px, 1fr));
    gap: 24px;
}

.menu-card {
    background: white;
    border: 1px solid #fef3c7;
    border-radius: 20px;
    padding: 24px;
    box-shadow: 0 4px 6px rgba(69, 26, 3, 0.02);
    display: flex;
    flex-direction: column;
    transition: transform 0.2s, box-shadow 0.2s;
}

.menu-card:hover {
    transform: translateY(-2px);
    box-shadow: 0 10px 15px rgba(69, 26, 3, 0.05);
}

.food-emoji {
    font-size: 40px;
    display: block;
    margin-bottom: 12px;
}

.menu-card h3 {
    font-size: 18px;
    margin: 0 0 6px 0;
    font-weight: 800;
}

.menu-card p {
    font-size: 13px;
    color: #78350f;
    line-height: 1.4;
    margin: 0 0 16px 0;
    flex-grow: 1;
}

.price-row {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-top: auto;
}

.price {
    font-size: 20px;
    font-weight: 900;
    color: #d97706;
}

.add-order-btn {
    background: #d97706;
    color: white;
    border: none;
    border-radius: 30px;
    padding: 8px 18px;
    font-weight: 700;
    cursor: pointer;
    transition: background 0.2s;
}

.add-order-btn:hover {
    background: #b45309;
}

.footer {
    background: #451a03;
    color: #fef3c7;
    text-align: center;
    padding: 40px 20px;
    margin-top: 100px;
    font-size: 14px;
}

.footer strong {
    color: #fcd34d;
}

.footer p {
    margin: 6px 0;
    opacity: 0.9;
}

js:
function filterMenu(category, btn) {
    // Update filter active button styling
    document.querySelectorAll('.filter-btn').forEach(b => b.classList.remove('active'));
    btn.classList.add('active');

    // Filter cards
    document.querySelectorAll('.menu-card').forEach(card => {
        if (category === 'all' || card.getAttribute('data-category') === category) {
            card.style.display = 'flex';
        } else {
            card.style.display = 'none';
        }
    });
}

function orderFood(itemName) {
    const businessName = "My Business";
    const phone = "919999999999";
    const text = encodeURIComponent("Hi " + businessName + ", I'd like to order " + itemName + " from the menu. Please confirm and let me know the preparation time.");
    const url = "https://wa.me/" + phone + "?text=" + text;
    window.open(url, "_blank");
}
